// Validate and clean incoming lead data
const input = $input.first().json.body || $input.first().json;

const name = (input.name || '').trim();
const email = (input.email || '').trim().toLowerCase();
const phone = (input.phone || '').trim();
const service = (input.service || '').trim();
const budget = (input.budget || '').trim();
const message = (input.message || '').trim();
const howHeard = (input['how-heard'] || '').trim();
const leadMagnet = input.lead_magnet === true || input.lead_magnet === 'true';
const submittedAt = input.submitted_at || new Date().toISOString();

// Basic email validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error('Invalid email address: ' + email);
}

// Generate lead ID
const leadId = 'DA-' + Date.now().toString(36).toUpperCase();

return [{
  json: {
    lead_id: leadId,
    name,
    email,
    phone,
    service,
    budget,
    message,
    how_heard: howHeard,
    lead_magnet: leadMagnet,
    submitted_at: submittedAt,
    source: leadMagnet ? 'lead_magnet' : 'contact_form'
  }
}];

// Lead Scoring Logic
const lead = $input.first().json;
let score = 0;
const tags = [];

// Budget scoring
switch (lead.budget) {
  case '4500-8000':
    score += 40;
    tags.push('high-budget');
    break;
  case '2000-4000':
    score += 25;
    tags.push('mid-budget');
    break;
  case '800-1500':
    score += 15;
    tags.push('starter-budget');
    break;
  case 'not-sure':
    score += 5;
    tags.push('budget-tbd');
    break;
}

// Service selected
if (lead.service) {
  score += 10;
  tags.push(lead.service);
}

// Phone provided (signals intent)
if (lead.phone) {
  score += 10;
  tags.push('phone-provided');
}

// Lead magnet download
if (lead.lead_magnet) {
  score += 15;
  tags.push('checklist-download');
}

// Message provided (engaged prospect)
if (lead.message && lead.message.length > 20) {
  score += 5;
  tags.push('detailed-message');
}

// Determine tier
let tier = 'cool';
if (score >= 40) tier = 'hot';
else if (score >= 20) tier = 'warm';

return [{
  json: {
    ...lead,
    score,
    tier,
    tags: tags.join(', '),
    nurture_stage: 0,
    last_email_sent: '',
    status: 'new'
  }
}];

